{
  "mode": "io",
  "tests": [
    {
      "name": "basic_case",
      "input": "customer1, service1\ncustomer2, service2\n",
      "output": "success\n",
      "notes": "Validates basic functionality with standard input."
    },
    {
      "name": "single_customer_multiple_services",
      "input": "customer1, service1\ncustomer1, service2\n",
      "output": "success\n",
      "notes": "Tests handling of multiple services for a single customer."
    },
    {
      "name": "multiple_customers_single_service",
      "input": "customer1, service1\ncustomer2, service1\n",
      "output": "success\n",
      "notes": "Validates multiple customers using the same service."
    },
    {
      "name": "no_customers",
      "input": "\n",
      "output": "no customers\n",
      "notes": "Edge case with no input data."
    },
    {
      "name": "invalid_format",
      "input": "customer1 service1\ncustomer2, service2\n",
      "output": "error: invalid format\n",
      "notes": "Tests error handling for incorrectly formatted input."
    },
    {
      "name": "duplicate_entries",
      "input": "customer1, service1\ncustomer1, service1\n",
      "output": "error: duplicate entry\n",
      "notes": "Checks for handling of duplicate customer-service pairs."
    },
    {
      "name": "long_input",
      "input": "customer1, service1\ncustomer2, service2\ncustomer3, service3\ncustomer4, service4\ncustomer5, service5\ncustomer6, service6\ncustomer7, service7\ncustomer8, service8\n",
      "output": "success\n",
      "notes": "Tests performance with a larger input set."
    },
    {
      "name": "special_characters",
      "input": "customer1!, service1@\ncustomer2#, service2$\n",
      "output": "success\n",
      "notes": "Validates handling of special characters in identifiers."
    }
  ],
  "assumptions": "Input is provided in the specified format and follows the constraints outlined in the problem statement.",
  "notes": "Ensure to test edge cases for robustness."
}
